#!/bin/bash
set -euo pipefail

SIMPLEX_DATA="/var/lib/lifeos/simplex"
SETUP_MARKER="${SIMPLEX_DATA}/.setup-done"

if [ -f "$SETUP_MARKER" ]; then
    echo "[lifeos-simplex-setup] Already configured"
    exit 0
fi

mkdir -p "$SIMPLEX_DATA"
chmod 0700 "$SIMPLEX_DATA"

# SimpleX CLI creates its database on first run.
# The invite link will be generated by lifeosd on first connection
# and displayed in the dashboard for the user to scan.

touch "$SETUP_MARKER"
echo "[lifeos-simplex-setup] Setup complete"
